const inputData = $input.first().json;
const products = inputData.body || inputData;
const productArray = Array.isArray(products) ? products : [products];

const productData = [];

for (const product of productArray) {
  // database_schema.sql의 products 테이블 컬럼에 맞게 매핑
  productData.push({
    json: {
      product_number: String(product.product_no),
      name: product.name,
      brand: product.brand || 'Unknown',
      category: 'beauty',
      subcategory: product.category || 'skincare',
      price: product.discounted_price || product.sales_price,
      original_price: product.sales_price,
      discount_rate: product.sales_price > 0 ? ((product.sales_price - (product.discounted_price || product.sales_price)) / product.sales_price * 100).toFixed(2) : 0,
      description: product.short_description || '',
      image_url: product.product_vertical_medium_url || '',
      product_url: product.url || '',
      status: 'active'
    }
  });
}

return productData;

const inputData = $input.first().json;
const products = inputData.body || inputData;
const productArray = Array.isArray(products) ? products : [products];

const reviewData = [];

for (const product of productArray) {
  if (product.reviews && Array.isArray(product.reviews)) {
    for (const review of product.reviews) {
      // database_schema.sql의 beauty_reviews 테이블에 맞게 매핑
      reviewData.push({
        json: {
          review_id: String(review.id || review.reviewId || Date.now() + Math.random()),
          product_number: String(product.product_no),
          content: review.contents || review.content,
          rating: review.rating || review.score || null,
          created_at: review.registeredAt || review.created_at || new Date().toISOString(),
          author: review.author?.name || review.authorName || 'Anonymous',
          like_count: review.like_count || review.likeCount || 0,
          verified_purchase: review.verified_purchase || false,
          skin_type: review.skin_type || review.attributes?.skin_type || null,
          age_group: review.age_group || review.attributes?.age_group || null
        }
      });
    }
  }
}

return reviewData;

const aiItems = $input.all();
const reviewNode = $('리뷰 추출');
const reviewItems = reviewNode.all();

const output = [];

for (let i = 0; i < aiItems.length; i++) {
  const aiOutput = aiItems[i].json.output || aiItems[i].json.text || '3';

  const scoreMatch = String(aiOutput).match(/[1-5]/);
  const score = scoreMatch ? parseInt(scoreMatch[0]) : 3;

  const reviewData = reviewItems[i]?.json || {};

  // 감성 라벨 매핑
  const sentimentLabels = {
    5: 'Very satisfied',
    4: 'Satisfied',
    3: 'Neutral',
    2: 'Dissatisfied',
    1: 'Very dissatisfied'
  };

  // database_schema.sql의 beauty_reviews 테이블 컬럼에 맞게 출력
  output.push({
    json: {
      review_id: reviewData.review_id,
      product_number: reviewData.product_number,
      content: reviewData.content,
      rating: reviewData.rating,
      created_at: reviewData.created_at,
      author: reviewData.author,
      like_count: reviewData.like_count,
      verified_purchase: reviewData.verified_purchase,
      skin_type: reviewData.skin_type,
      age_group: reviewData.age_group,
      sentiment_score: score,
      sentiment_label: sentimentLabels[score],
      emotions: JSON.stringify({score: score, label: sentimentLabels[score]}),
      key_points: JSON.stringify([]),
      absa_aspects: JSON.stringify([]),
      processed_at: new Date().toISOString()
    }
  });
}

return output;
